INSERT INTO public.sentences (id,list_id,ru,ru_stressed,translit,en,pl,de,sort_order) VALUES
('hangingout-part-1-1','hangingout-part-1','Я встречаюсь с друзьями.','Я встреча́юсь с друзья́ми.','Ya vstrechayus s druzyami.','I meet my friends.','Spotykam się z przyjaciółmi.','Ich treffe meine Freunde.',1),
('hangingout-part-1-2','hangingout-part-1','Мы часто проводим время вместе.','Мы ча́сто прово́дим вре́мя вме́сте.','My chasto provodim vremya vmeste.','We often spend time together.','Często spędzamy razem czas.','Wir verbringen oft Zeit zusammen.',2),
('hangingout-part-1-3','hangingout-part-1','Мы идём в кафе.','Мы идём в кафе́.','My idyom v kafe.','We go to a café.','Idziemy do kawiarni.','Wir gehen in ein Café.',3),
('hangingout-part-1-4','hangingout-part-1','Мы пьём кофе.','Мы пьём ко́фе.','My pyom kofe.','We drink coffee.','Pijemy kawę.','Wir trinken Kaffee.',4),
('hangingout-part-1-5','hangingout-part-1','Мы разговариваем.','Мы разгова́риваем.','My razgovarivayem.','We talk.','Rozmawiamy.','Wir reden.',5),
('hangingout-part-1-6','hangingout-part-1','Мы смеёмся вместе.','Мы смеёмся вме́сте.','My smeyomsya vmeste.','We laugh together.','Śmiejemy się razem.','Wir lachen zusammen.',6),
('hangingout-part-1-7','hangingout-part-1','Я звоню своему другу.','Я звоню́ своему́ дру́гу.','Ya zvonyu svoyemu drugu.','I call my friend.','Dzwonię do mojego przyjaciela.','Ich rufe meinen Freund an.',7),
('hangingout-part-1-8','hangingout-part-1','Мы встречаемся вечером.','Мы встреча́емся ве́чером.','My vstrechayemsya vecherom.','We meet in the evening.','Spotykamy się wieczorem.','Wir treffen uns am Abend.',8),
('hangingout-part-1-9','hangingout-part-1','Мы гуляем по городу.','Мы гуля́ем по го́роду.','My gulyayem po gorodu.','We walk around the city.','Spacerujemy po mieście.','Wir gehen durch die Stadt.',9),
('hangingout-part-1-10','hangingout-part-1','Мы сидим в парке.','Мы сиди́м в па́рке.','My sidim v parke.','We sit in the park.','Siedzimy w parku.','Wir sitzen im Park.',10),
('hangingout-part-1-11','hangingout-part-1','Погода хорошая.','Пого́да хоро́шая.','Pogoda khoroshaya.','The weather is nice.','Pogoda jest ładna.','Das Wetter ist schön.',11),
('hangingout-part-1-12','hangingout-part-1','Мы наслаждаемся днём.','Мы наслажда́емся днём.','My naslazhdayemsya dnyom.','We enjoy the day.','Cieszymy się dniem.','Wir genießen den Tag.',12),
('hangingout-part-1-13','hangingout-part-1','Мы обсуждаем работу.','Мы обсужда́ем рабо́ту.','My obsuzhdayem rabotu.','We talk about work.','Rozmawiamy o pracy.','Wir sprechen über die Arbeit.',13),
('hangingout-part-1-14','hangingout-part-1','Мы обсуждаем учёбу.','Мы обсужда́ем учёбу.','My obsuzhdayem uchyobu.','We talk about school.','Rozmawiamy o szkole.','Wir sprechen über die Schule.',14),
('hangingout-part-1-15','hangingout-part-1','Мы рассказываем истории.','Мы расска́зываем исто́рии.','My rasskazyvayem istorii.','We tell stories.','Opowiadamy historie.','Wir erzählen Geschichten.',15),
('hangingout-part-1-16','hangingout-part-1','Мой друг очень смешной.','Мой друг о́чень смешно́й.','Moy drug ochen smeshnoy.','My friend is very funny.','Mój przyjaciel jest bardzo zabawny.','Mein Freund ist sehr lustig.',16),
('hangingout-part-1-17','hangingout-part-1','Мы смотрим на людей.','Мы смо́трим на люде́й.','My smotrim na lyudey.','We watch people.','Obserwujemy ludzi.','Wir beobachten Leute.',17),
('hangingout-part-1-18','hangingout-part-1','Мы едим мороженое.','Мы еди́м моро́женое.','My yedim morozhenoye.','We eat ice cream.','Jemy lody.','Wir essen Eis.',18),
('hangingout-part-1-19','hangingout-part-1','Мы отдыхаем.','Мы отдыха́ем.','My otdykhayem.','We relax.','Odpoczywamy.','Wir entspannen uns.',19),
('hangingout-part-1-20','hangingout-part-1','Мы хорошо проводим время.','Мы хорошо́ прово́дим вре́мя.','My khorosho provodim vremya.','We have a good time.','Dobrze się bawimy.','Wir haben eine gute Zeit.',20),
('hangingout-part-1-21','hangingout-part-1','Мы идём в кино.','Мы идём в кино́.','My idyom v kino.','We go to the cinema.','Idziemy do kina.','Wir gehen ins Kino.',21),
('hangingout-part-1-22','hangingout-part-1','Фильм очень интересный.','Фильм о́чень интере́сный.','Film ochen interesnyy.','The movie is very interesting.','Film jest bardzo interesujący.','Der Film ist sehr interessant.',22),
('hangingout-part-1-23','hangingout-part-1','Мы покупаем билеты.','Мы покупа́ем биле́ты.','My pokupayem bilety.','We buy tickets.','Kupujemy bilety.','Wir kaufen Tickets.',23),
('hangingout-part-1-24','hangingout-part-1','Мы сидим рядом.','Мы сиди́м ря́дом.','My sidim ryadom.','We sit next to each other.','Siedzimy obok siebie.','Wir sitzen nebeneinander.',24),
('hangingout-part-1-25','hangingout-part-1','После фильма мы обсуждаем его.','По́сле фи́льма мы обсужда́ем его́.','Posle filma my obsuzhdayem yego.','After the movie, we talk about it.','Po filmie rozmawiamy o nim.','Nach dem Film sprechen wir darüber.',25),
('hangingout-part-1-26','hangingout-part-1','Мы играем в настольные игры.','Мы игра́ем в насто́льные и́гры.','My igrayem v nastolnye igry.','We play board games.','Gramy w gry planszowe.','Wir spielen Brettspiele.',26),
('hangingout-part-1-27','hangingout-part-1','Мой друг выигрывает.','Мой друг выи́грывает.','Moy drug vyigryvayet.','My friend wins.','Mój przyjaciel wygrywa.','Mein Freund gewinnt.',27),
('hangingout-part-1-28','hangingout-part-1','Мы снова играем.','Мы сно́ва игра́ем.','My snova igrayem.','We play again.','Gramy ponownie.','Wir spielen noch einmal.',28),
('hangingout-part-1-29','hangingout-part-1','Мы слушаем музыку.','Мы слу́шаем му́зыку.','My slushayem muzyku.','We listen to music.','Słuchamy muzyki.','Wir hören Musik.',29),
('hangingout-part-1-30','hangingout-part-1','Мне нравится эта песня.','Мне нра́вится э́та пе́сня.','Mne nravitsya eta pesnya.','I like this song.','Podoba mi się ta piosenka.','Ich mag dieses Lied.',30),
('hangingout-part-1-31','hangingout-part-1','Мы поём вместе.','Мы поём вме́сте.','My poyom vmeste.','We sing together.','Śpiewamy razem.','Wir singen zusammen.',31),
('hangingout-part-1-32','hangingout-part-1','Мы идём в торговый центр.','Мы идём в торго́вый це́нтр.','My idyom v torgovyy tsentr.','We go to the shopping mall.','Idziemy do centrum handlowego.','Wir gehen ins Einkaufszentrum.',32),
('hangingout-part-1-33','hangingout-part-1','Мы смотрим магазины.','Мы смо́трим магази́ны.','My smotrim magaziny.','We look around the shops.','Oglądamy sklepy.','Wir schauen uns die Geschäfte an.',33),
('hangingout-part-1-34','hangingout-part-1','Я ничего не покупаю.','Я ничего́ не покупа́ю.','Ya nichego ne pokupayu.','I do not buy anything.','Nic nie kupuję.','Ich kaufe nichts.',34),
('hangingout-part-1-35','hangingout-part-1','Мы просто гуляем.','Мы про́сто гуля́ем.','My prosto gulyayem.','We are just hanging out.','Po prostu spędzamy razem czas.','Wir hängen einfach zusammen ab.',35),
('hangingout-part-1-36','hangingout-part-1','Мы идём в ресторан.','Мы идём в рестора́н.','My idyom v restoran.','We go to a restaurant.','Idziemy do restauracji.','Wir gehen in ein Restaurant.',36),
('hangingout-part-1-37','hangingout-part-1','Мы заказываем еду.','Мы зака́зываем еду́.','My zakazyvayem yedu.','We order food.','Zamawiamy jedzenie.','Wir bestellen Essen.',37),
('hangingout-part-1-38','hangingout-part-1','Еда очень вкусная.','Еда́ о́чень вку́сная.','Yeda ochen vkusnaya.','The food is delicious.','Jedzenie jest pyszne.','Das Essen ist lecker.',38),
('hangingout-part-1-39','hangingout-part-1','Мы делимся едой.','Мы де́лимся едо́й.','My delimsya yedoy.','We share food.','Dzielimy się jedzeniem.','Wir teilen das Essen.',39),
('hangingout-part-1-40','hangingout-part-1','Мы говорим о путешествиях.','Мы говори́м о путеше́ствиях.','My govorim o puteshestviyakh.','We talk about traveling.','Rozmawiamy o podróżach.','Wir sprechen über Reisen.',40),
('hangingout-part-1-41','hangingout-part-1','Мы планируем отпуск.','Мы плани́руем о́тпуск.','My planiruyem otpusk.','We plan a vacation.','Planujemy wakacje.','Wir planen einen Urlaub.',41),
('hangingout-part-1-42','hangingout-part-1','Мы встречаем новых людей.','Мы встреча́ем но́вых люде́й.','My vstrechayem novykh lyudey.','We meet new people.','Poznajemy nowych ludzi.','Wir lernen neue Leute kennen.',42),
('hangingout-part-1-43','hangingout-part-1','Они очень дружелюбные.','Они́ о́чень дружелю́бные.','Oni ochen druzhelyubnye.','They are very friendly.','Są bardzo przyjaźni.','Sie sind sehr freundlich.',43),
('hangingout-part-1-44','hangingout-part-1','Мы обмениваемся номерами телефонов.','Мы обме́ниваемся номера́ми телефо́нов.','My obmenivayemsya nomerami telefonov.','We exchange phone numbers.','Wymieniamy się numerami telefonów.','Wir tauschen Telefonnummern aus.',44),
('hangingout-part-1-45','hangingout-part-1','Мы остаёмся на связи.','Мы остаёмся на свя́зи.','My ostayomsya na svyazi.','We stay in touch.','Pozostajemy w kontakcie.','Wir bleiben in Kontakt.',45),
('hangingout-part-1-46','hangingout-part-1','Мы делаем селфи.','Мы де́лаем се́лфи.','My delayem selfi.','We take a selfie.','Robimy selfie.','Wir machen ein Selfie.',46),
('hangingout-part-1-47','hangingout-part-1','Фотография получилась хорошей.','Фотогра́фия получи́лась хоро́шей.','Fotografiya poluchilas khoroshey.','The photo turned out well.','Zdjęcie wyszło dobrze.','Das Foto ist gut geworden.',47),
('hangingout-part-1-48','hangingout-part-1','Мы публикуем её в интернете.','Мы публику́ем её в интерне́те.','My publikuyem yeyo v internete.','We post it online.','Publikujemy je w internecie.','Wir posten es online.',48),
('hangingout-part-1-49','hangingout-part-1','Мы получаем много лайков.','Мы получа́ем мно́го ла́йков.','My poluchayem mnogo laykov.','We get many likes.','Dostajemy dużo polubień.','Wir bekommen viele Likes.',49),
('hangingout-part-1-50','hangingout-part-1','Это был отличный вечер.','Э́то был отли́чный ве́чер.','Eto byl otlichnyy vecher.','It was a great evening.','To był świetny wieczór.','Es war ein toller Abend.',50),
('hangingout-part-1-51','hangingout-part-1','Мы встречаемся в выходные.','Мы встреча́емся в выходны́е.','My vstrechayemsya v vykhodnye.','We meet on weekends.','Spotykamy się w weekendy.','Wir treffen uns am Wochenende.',51),
('hangingout-part-1-52','hangingout-part-1','Мы часто собираемся по субботам.','Мы ча́сто собира́емся по суббо́там.','My chasto sobirayemsya po subbotam.','We often get together on Saturdays.','Często spotykamy się w soboty.','Wir treffen uns oft samstags.',52),
('hangingout-part-1-53','hangingout-part-1','Мы играем в видеоигры.','Мы игра́ем в видеои́гры.','My igrayem v videoigry.','We play video games.','Gramy w gry wideo.','Wir spielen Videospiele.',53),
('hangingout-part-1-54','hangingout-part-1','Мой друг очень хорошо играет.','Мой друг о́чень хорошо́ игра́ет.','Moy drug ochen khorosho igrayet.','My friend plays very well.','Mój przyjaciel gra bardzo dobrze.','Mein Freund spielt sehr gut.',54),
('hangingout-part-1-55','hangingout-part-1','Мы соревнуемся друг с другом.','Мы соревну́емся друг с дру́гом.','My sorevnuyemsya drug s drugom.','We compete with each other.','Rywalizujemy ze sobą.','Wir treten gegeneinander an.',55),
('hangingout-part-1-56','hangingout-part-1','Мы смотрим спортивный матч.','Мы смо́трим спорти́вный матч.','My smotrim sportivnyy match.','We watch a sports match.','Oglądamy mecz sportowy.','Wir schauen ein Sportspiel.',56),
('hangingout-part-1-57','hangingout-part-1','Наша команда выигрывает.','На́ша кома́нда выи́грывает.','Nasha komanda vyigryvayet.','Our team wins.','Nasza drużyna wygrywa.','Unser Team gewinnt.',57),
('hangingout-part-1-58','hangingout-part-1','Мы очень рады.','Мы о́чень ра́ды.','My ochen rady.','We are very happy.','Jesteśmy bardzo szczęśliwi.','Wir sind sehr glücklich.',58),
('hangingout-part-1-59','hangingout-part-1','Мы сидим у меня дома.','Мы сиди́м у меня́ до́ма.','My sidim u menya doma.','We hang out at my house.','Spędzamy czas u mnie w domu.','Wir hängen bei mir zu Hause ab.',59),
('hangingout-part-1-60','hangingout-part-1','Мы смотрим телевизор.','Мы смо́трим телеви́зор.','My smotrim televizor.','We watch TV.','Oglądamy telewizję.','Wir schauen fern.',60),
('hangingout-part-1-61','hangingout-part-1','Мы обсуждаем новости.','Мы обсужда́ем но́вости.','My obsuzhdayem novosti.','We discuss the news.','Rozmawiamy o wiadomościach.','Wir diskutieren die Nachrichten.',61),
('hangingout-part-1-62','hangingout-part-1','Мы рассказываем шутки.','Мы расска́зываем шу́тки.','My rasskazyvayem shutki.','We tell jokes.','Opowiadamy dowcipy.','Wir erzählen Witze.',62),
('hangingout-part-1-63','hangingout-part-1','Все смеются.','Все́ смею́тся.','Vsye smeyutsya.','Everyone laughs.','Wszyscy się śmieją.','Alle lachen.',63),
('hangingout-part-1-64','hangingout-part-1','Мы решаем заказать пиццу.','Мы реша́ем заказа́ть пи́ццу.','My reshayem zakazat pitstsu.','We decide to order pizza.','Decydujemy się zamówić pizzę.','Wir beschließen, Pizza zu bestellen.',64),
('hangingout-part-1-65','hangingout-part-1','Пицца приходит быстро.','Пи́цца прихо́дит бы́стро.','Pitstsa prikhodit bystro.','The pizza arrives quickly.','Pizza przychodzi szybko.','Die Pizza kommt schnell an.',65),
('hangingout-part-1-66','hangingout-part-1','Мы едим вместе.','Мы еди́м вме́сте.','My yedim vmeste.','We eat together.','Jemy razem.','Wir essen zusammen.',66),
('hangingout-part-1-67','hangingout-part-1','Мы говорим о музыке.','Мы говори́м о му́зыке.','My govorim o muzyke.','We talk about music.','Rozmawiamy o muzyce.','Wir sprechen über Musik.',67),
('hangingout-part-1-68','hangingout-part-1','У нас похожие вкусы.','У нас похо́жие вку́сы.','U nas pokhozhie vkusy.','We have similar tastes.','Mamy podobny gust.','Wir haben einen ähnlichen Geschmack.',68),
('hangingout-part-1-69','hangingout-part-1','Мы создаём общий плейлист.','Мы создаём о́бщий пле́йлист.','My sozdayom obshchiy pleylist.','We create a shared playlist.','Tworzymy wspólną playlistę.','Wir erstellen eine gemeinsame Playlist.',69),
('hangingout-part-1-70','hangingout-part-1','Мы слушаем любимые песни.','Мы слу́шаем люби́мые пе́сни.','My slushayem lyubimye pesni.','We listen to our favorite songs.','Słuchamy naszych ulubionych piosenek.','Wir hören unsere Lieblingslieder.',70),
('hangingout-part-1-71','hangingout-part-1','Мы идём в боулинг.','Мы идём в бо́улинг.','My idyom v bouling.','We go bowling.','Idziemy na kręgle.','Wir gehen bowlen.',71),
('hangingout-part-1-72','hangingout-part-1','Я сбиваю все кегли.','Я сбива́ю все ке́гли.','Ya sbivayu vse kegli.','I knock down all the pins.','Strącam wszystkie kręgle.','Ich werfe alle Kegel um.',72),
('hangingout-part-1-73','hangingout-part-1','Мои друзья аплодируют.','Мои́ друзья́ аплоди́руют.','Moi druzya aplodiruyut.','My friends applaud.','Moi przyjaciele klaszczą.','Meine Freunde applaudieren.',73),
('hangingout-part-1-74','hangingout-part-1','Мы веселимся весь вечер.','Мы весели́мся весь ве́чер.','My veselimsya ves vecher.','We have fun all evening.','Bawimy się cały wieczór.','Wir haben den ganzen Abend Spaß.',74),
('hangingout-part-1-75','hangingout-part-1','Мы идём на концерт.','Мы идём на конце́рт.','My idyom na kontsert.','We go to a concert.','Idziemy na koncert.','Wir gehen zu einem Konzert.',75),
('hangingout-part-1-76','hangingout-part-1','Музыка звучит отлично.','Му́зыка звучи́т отли́чно.','Muzyka zvuchit otlichno.','The music sounds great.','Muzyka brzmi świetnie.','Die Musik klingt großartig.',76),
('hangingout-part-1-77','hangingout-part-1','Мы танцуем вместе.','Мы танцу́ем вме́сте.','My tantsuyem vmeste.','We dance together.','Tańczymy razem.','Wir tanzen zusammen.',77),
('hangingout-part-1-78','hangingout-part-1','Мы поём слова песни.','Мы поём слова́ пе́сни.','My poyom slova pesni.','We sing the song lyrics.','Śpiewamy słowa piosenki.','Wir singen den Liedtext mit.',78),
('hangingout-part-1-79','hangingout-part-1','Концерт заканчивается поздно.','Конце́рт зака́нчивается по́здно.','Kontsert zakanchivayetsya pozdno.','The concert ends late.','Koncert kończy się późno.','Das Konzert endet spät.',79),
('hangingout-part-1-80','hangingout-part-1','Мы возвращаемся домой счастливыми.','Мы возвраща́емся домо́й счастли́выми.','My vozvrashchayemsya domoy schastlivymi.','We return home happy.','Wracamy do domu szczęśliwi.','Wir kehren glücklich nach Hause zurück.',80),
('hangingout-part-1-81','hangingout-part-1','Иногда мы устраиваем пикник.','Иногда́ мы устра́иваем пикни́к.','Inogda my ustraivayem piknik.','Sometimes we have a picnic.','Czasami urządzamy piknik.','Manchmal machen wir ein Picknick.',81),
('hangingout-part-1-82','hangingout-part-1','Мы приносим еду и напитки.','Мы прино́сим еду́ и напи́тки.','My prinosim yedu i napitki.','We bring food and drinks.','Przynosimy jedzenie i napoje.','Wir bringen Essen und Getränke mit.',82),
('hangingout-part-1-83','hangingout-part-1','Мы сидим на траве.','Мы сиди́м на траве́.','My sidim na trave.','We sit on the grass.','Siedzimy na trawie.','Wir sitzen auf dem Gras.',83),
('hangingout-part-1-84','hangingout-part-1','Мы играем в мяч.','Мы игра́ем в мяч.','My igrayem v myach.','We play with a ball.','Gramy w piłkę.','Wir spielen Ball.',84),
('hangingout-part-1-85','hangingout-part-1','Все участвуют.','Все́ уча́ствуют.','Vsye uchastvuyut.','Everyone joins in.','Wszyscy biorą udział.','Alle machen mit.',85),
('hangingout-part-1-86','hangingout-part-1','Мы фотографируемся.','Мы фотографи́руемся.','My fotografiruyemsya.','We take photos.','Robimy zdjęcia.','Wir machen Fotos.',86),
('hangingout-part-1-87','hangingout-part-1','День проходит быстро.','День прохо́дит бы́стро.','Den prokhodit bystro.','The day goes by quickly.','Dzień mija szybko.','Der Tag vergeht schnell.',87),
('hangingout-part-1-88','hangingout-part-1','Мы не хотим уходить.','Мы не хоти́м уходи́ть.','My ne khotim ukhudit.','We do not want to leave.','Nie chcemy wychodzić.','Wir wollen nicht gehen.',88),
('hangingout-part-1-89','hangingout-part-1','Мы планируем следующую встречу.','Мы плани́руем сле́дующую встре́чу.','My planiruyem sleduyushchuyu vstrechu.','We plan our next meeting.','Planujemy następne spotkanie.','Wir planen unser nächstes Treffen.',89),
('hangingout-part-1-90','hangingout-part-1','Мои друзья очень важны для меня.','Мои́ друзья́ о́чень ва́жны для меня́.','Moi druzya ochen vazhny dlya menya.','My friends are very important to me.','Moi przyjaciele są dla mnie bardzo ważni.','Meine Freunde sind mir sehr wichtig.',90),
('hangingout-part-1-91','hangingout-part-1','Мы поддерживаем друг друга.','Мы подде́рживаем друг дру́га.','My podderzhivayem drug druga.','We support each other.','Wspieramy się nawzajem.','Wir unterstützen uns gegenseitig.',91),
('hangingout-part-1-92','hangingout-part-1','Мы делимся своими проблемами.','Мы де́лимся свои́ми пробле́мами.','My delimsya svoimi problemami.','We share our problems.','Dzielimy się swoimi problemami.','Wir teilen unsere Probleme miteinander.',92),
('hangingout-part-1-93','hangingout-part-1','Мы даём хорошие советы.','Мы даём хоро́шие сове́ты.','My dayom khoroshie sovety.','We give good advice.','Dajemy dobre rady.','Wir geben gute Ratschläge.',93),
('hangingout-part-1-94','hangingout-part-1','Мы доверяем друг другу.','Мы доверя́ем друг дру́гу.','My doveryayem drug drugu.','We trust each other.','Ufam sobie nawzajem.','Wir vertrauen einander.',94),
('hangingout-part-1-95','hangingout-part-1','Мы часто переписываемся.','Мы ча́сто перепи́сываемся.','My chasto perepisyvayemsya.','We text each other often.','Często do siebie piszemy.','Wir schreiben uns oft.',95),
('hangingout-part-1-96','hangingout-part-1','Мы отправляем смешные сообщения.','Мы отправля́ем смешны́е сообще́ния.','My otpravlyayem smeshnye soobshcheniya.','We send funny messages.','Wysyłamy zabawne wiadomości.','Wir schicken lustige Nachrichten.',96),
('hangingout-part-1-97','hangingout-part-1','Мы используем групповой чат.','Мы испо́льзуем группово́й чат.','My ispolzuyem gruppovoy chat.','We use a group chat.','Używamy czatu grupowego.','Wir nutzen einen Gruppenchat.',97),
('hangingout-part-1-98','hangingout-part-1','Там всегда происходит что-то интересное.','Там всегда́ происхо́дит что́-то интере́сное.','Tam vsegda proiskhodit chto-to interesnoye.','Something interesting is always happening there.','Zawsze dzieje się tam coś ciekawego.','Dort passiert immer etwas Interessantes.',98),
('hangingout-part-1-99','hangingout-part-1','Мы никогда не скучаем.','Мы никогда́ не скуча́ем.','My nikogda ne skuchayem.','We are never bored.','Nigdy się nie nudzimy.','Wir langweilen uns nie.',99),
('hangingout-part-1-100','hangingout-part-1','Мне нравится проводить время с друзьями.','Мне нра́вится проводи́ть вре́мя с друзья́ми.','Mne nravitsya provodit vremya s druzyami.','I like spending time with friends.','Lubię spędzać czas z przyjaciółmi.','Ich verbringe gern Zeit mit Freunden.',100),
('hangingout-part-1-101','hangingout-part-1','Вчера мы встретились после работы.','Вчера́ мы встре́тились по́сле рабо́ты.','Vchera my vstretilis posle raboty.','Yesterday we met after work.','Wczoraj spotkaliśmy się po pracy.','Gestern haben wir uns nach der Arbeit getroffen.',101),
('hangingout-part-1-102','hangingout-part-1','Мы пошли в новый бар.','Мы пошли́ в но́вый бар.','My poshli v novyy bar.','We went to a new bar.','Poszliśmy do nowego baru.','Wir gingen in eine neue Bar.',102),
('hangingout-part-1-103','hangingout-part-1','Там было много людей.','Там бы́ло мно́го люде́й.','Tam bylo mnogo lyudey.','There were many people there.','Było tam dużo ludzi.','Dort waren viele Leute.',103),
('hangingout-part-1-104','hangingout-part-1','Мы нашли свободный столик.','Мы нашли́ свобо́дный сто́лик.','My nashli svobodnyy stolik.','We found a free table.','Znaleźliśmy wolny stolik.','Wir fanden einen freien Tisch.',104),
('hangingout-part-1-105','hangingout-part-1','Мы сидели и разговаривали.','Мы сиде́ли и разгова́ривали.','My sideli i razgovarivali.','We sat and talked.','Siedzieliśmy i rozmawialiśmy.','Wir saßen und unterhielten uns.',105),
('hangingout-part-1-106','hangingout-part-1','Время прошло очень быстро.','Вре́мя прошло́ о́чень бы́стро.','Vremya proshlo ochen bystro.','Time passed very quickly.','Czas minął bardzo szybko.','Die Zeit verging sehr schnell.',106),
('hangingout-part-1-107','hangingout-part-1','Мы встретили старого друга.','Мы встре́тили ста́рого дру́га.','My vstretili starogo druga.','We met an old friend.','Spotkaliśmy starego przyjaciela.','Wir trafen einen alten Freund.',107),
('hangingout-part-1-108','hangingout-part-1','Он присоединился к нам.','Он присоедини́лся к нам.','On prisoyedinilsya k nam.','He joined us.','Dołączył do nas.','Er schloss sich uns an.',108),
('hangingout-part-1-109','hangingout-part-1','Мы вспоминали школьные годы.','Мы вспомина́ли шко́льные го́ды.','My vspominali shkolnye gody.','We remembered our school years.','Wspominaliśmy lata szkolne.','Wir erinnerten uns an die Schulzeit.',109),
('hangingout-part-1-110','hangingout-part-1','Это было очень весело.','Э́то бы́ло о́чень весело́.','Eto bylo ochen veselo.','It was very fun.','To było bardzo zabawne.','Es war sehr lustig.',110),
('hangingout-part-1-111','hangingout-part-1','Мы гуляли вдоль реки.','Мы гуля́ли вдоль реки́.','My gulyali vdol reki.','We walked along the river.','Spacerowaliśmy wzdłuż rzeki.','Wir gingen am Fluss entlang.',111),
('hangingout-part-1-112','hangingout-part-1','Вечером было красиво.','Ве́чером бы́ло краси́во.','Vecherom bylo krasivo.','The evening was beautiful.','Wieczór był piękny.','Der Abend war schön.',112),
('hangingout-part-1-113','hangingout-part-1','Мы смотрели на закат.','Мы смотре́ли на зака́т.','My smotreli na zakat.','We watched the sunset.','Patrzyliśmy na zachód słońca.','Wir sahen uns den Sonnenuntergang an.',113),
('hangingout-part-1-114','hangingout-part-1','Мой друг сделал фотографию.','Мой друг сде́лал фотогра́фию.','Moy drug sdelal fotografiyu.','My friend took a photo.','Mój przyjaciel zrobił zdjęcie.','Mein Freund machte ein Foto.',114),
('hangingout-part-1-115','hangingout-part-1','Фотография получилась прекрасной.','Фотогра́фия получи́лась прекра́сной.','Fotografiya poluchilas prekrasnoy.','The photo turned out beautiful.','Zdjęcie wyszło pięknie.','Das Foto wurde wunderschön.',115),
('hangingout-part-1-116','hangingout-part-1','Мы часто встречаемся летом.','Мы ча́сто встреча́емся ле́том.','My chasto vstrechayemsya letom.','We often meet in summer.','Często spotykamy się latem.','Wir treffen uns oft im Sommer.',116),
('hangingout-part-1-117','hangingout-part-1','Мы катаемся на велосипедах.','Мы ката́емся на велосипе́дах.','My katayemsya na velosipedakh.','We ride bicycles.','Jeździmy na rowerach.','Wir fahren Fahrrad.',117),
('hangingout-part-1-118','hangingout-part-1','Мы едем в парк.','Мы е́дем в парк.','My yedem v park.','We go to the park.','Jedziemy do parku.','Wir fahren in den Park.',118),
('hangingout-part-1-119','hangingout-part-1','Там много зелени.','Там мно́го зе́лени.','Tam mnogo zeleni.','There is a lot of greenery there.','Jest tam dużo zieleni.','Dort gibt es viel Grün.',119),
('hangingout-part-1-120','hangingout-part-1','Мы наслаждаемся свежим воздухом.','Мы наслажда́емся све́жим во́здухом.','My naslazhdayemsya svezhim vozdukhom.','We enjoy the fresh air.','Cieszymy się świeżym powietrzem.','Wir genießen die frische Luft.',120),
('hangingout-part-1-121','hangingout-part-1','Иногда мы играем в карты.','Иногда́ мы игра́ем в ка́рты.','Inogda my igrayem v karty.','Sometimes we play cards.','Czasami gramy w karty.','Manchmal spielen wir Karten.',121),
('hangingout-part-1-122','hangingout-part-1','Мой друг знает много игр.','Мой друг зна́ет мно́го игр.','Moy drug znayet mnogo igr.','My friend knows many games.','Mój przyjaciel zna wiele gier.','Mein Freund kennt viele Spiele.',122),
('hangingout-part-1-123','hangingout-part-1','Мы учим друг друга правилам.','Мы у́чим друг дру́га пра́вилам.','My uchim drug druga pravilam.','We teach each other the rules.','Uczymy się nawzajem zasad.','Wir bringen uns gegenseitig die Regeln bei.',123),
('hangingout-part-1-124','hangingout-part-1','Все хотят выиграть.','Все́ хотя́т выи́грать.','Vsye khotyat vyigrat.','Everyone wants to win.','Wszyscy chcą wygrać.','Alle wollen gewinnen.',124),
('hangingout-part-1-125','hangingout-part-1','Но главное — это веселье.','Но гла́вное — э́то весе́лье.','No glavnoye — eto veselye.','But the main thing is having fun.','Ale najważniejsza jest zabawa.','Aber das Wichtigste ist der Spaß.',125),
('hangingout-part-1-126','hangingout-part-1','Мы любим проводить время на улице.','Мы лю́бим проводи́ть вре́мя на у́лице.','My lyubim provodit vremya na ulitse.','We like spending time outdoors.','Lubimy spędzać czas na świeżym powietrzu.','Wir verbringen gerne Zeit draußen.',126),
('hangingout-part-1-127','hangingout-part-1','Погода сегодня идеальная.','Пого́да сего́дня идеа́льная.','Pogoda segodnya idealnaya.','The weather is perfect today.','Pogoda jest dziś idealna.','Das Wetter ist heute perfekt.',127),
('hangingout-part-1-128','hangingout-part-1','Мы сидим на террасе.','Мы сиди́м на терра́се.','My sidim na terrase.','We sit on the terrace.','Siedzimy na tarasie.','Wir sitzen auf der Terrasse.',128),
('hangingout-part-1-129','hangingout-part-1','Мы пьём лимонад.','Мы пьём лимона́д.','My pyom limonad.','We drink lemonade.','Pijemy lemoniadę.','Wir trinken Limonade.',129),
('hangingout-part-1-130','hangingout-part-1','Мы рассказываем смешные истории.','Мы расска́зываем смешны́е исто́рии.','My rasskazyvayem smeshnye istorii.','We tell funny stories.','Opowiadamy zabawne historie.','Wir erzählen lustige Geschichten.',130),
('hangingout-part-1-131','hangingout-part-1','Все внимательно слушают.','Все́ внима́тельно слу́шают.','Vsye vnimatelno slushayut.','Everyone listens carefully.','Wszyscy słuchają uważnie.','Alle hören aufmerksam zu.',131),
('hangingout-part-1-132','hangingout-part-1','Мы обсуждаем планы на будущее.','Мы обсужда́ем пла́ны на бу́дущее.','My obsuzhdayem plany na budushcheye.','We discuss future plans.','Rozmawiamy o planach na przyszłość.','Wir sprechen über Zukunftspläne.',132),
('hangingout-part-1-133','hangingout-part-1','Мы хотим путешествовать вместе.','Мы хоти́м путеше́ствовать вме́сте.','My khotim puteshestvovat vmeste.','We want to travel together.','Chcemy podróżować razem.','Wir möchten zusammen reisen.',133),
('hangingout-part-1-134','hangingout-part-1','Это звучит интересно.','Э́то звучи́т интере́сно.','Eto zvuchit interesno.','That sounds interesting.','To brzmi interesująco.','Das klingt interessant.',134),
('hangingout-part-1-135','hangingout-part-1','Мы выбираем возможные направления.','Мы выбира́ем возмо́жные направле́ния.','My vybirayem vozmozhnye napravleniya.','We choose possible destinations.','Wybieramy możliwe kierunki podróży.','Wir wählen mögliche Reiseziele aus.',135),
('hangingout-part-1-136','hangingout-part-1','Каждый предлагает свои идеи.','Ка́ждый предлага́ет свои́ иде́и.','Kazhdyy predlagayet svoi idei.','Everyone suggests their ideas.','Każdy proponuje swoje pomysły.','Jeder schlägt seine Ideen vor.',136),
('hangingout-part-1-137','hangingout-part-1','Мы любим проводить время вместе.','Мы лю́бим проводи́ть вре́мя вме́сте.','My lyubim provodit vremya vmeste.','We love spending time together.','Uwielbiamy spędzać razem czas.','Wir verbringen gerne Zeit zusammen.',137),
('hangingout-part-1-138','hangingout-part-1','Каждая встреча особенная.','Ка́ждая встре́ча осо́бенная.','Kazhdaya vstrecha osobennaya.','Every meeting is special.','Każde spotkanie jest wyjątkowe.','Jedes Treffen ist besonders.',138),
('hangingout-part-1-139','hangingout-part-1','Мы всегда находим чем заняться.','Мы всегда́ нахо́дим чем заня́ться.','My vsegda nakhodim chem zanyatsya.','We always find something to do.','Zawsze znajdujemy coś do zrobienia.','Wir finden immer etwas zu tun.',139),
('hangingout-part-1-140','hangingout-part-1','Нам никогда не скучно.','Нам никогда́ не ску́чно.','Nam nikogda ne skuchno.','We are never bored.','Nigdy się nie nudzimy.','Uns ist nie langweilig.',140),
('hangingout-part-1-141','hangingout-part-1','Мы часто смеёмся до слёз.','Мы ча́сто смеёмся до слёз.','My chasto smeyomsya do slyoz.','We often laugh until we cry.','Często śmiejemy się do łez.','Wir lachen oft bis zu den Tränen.',141),
('hangingout-part-1-142','hangingout-part-1','Это делает нас ближе.','Э́то де́лает нас бли́же.','Eto delayet nas blizhe.','It brings us closer.','To nas zbliża.','Das bringt uns näher zusammen.',142),
('hangingout-part-1-143','hangingout-part-1','Мы ценим нашу дружбу.','Мы це́ним на́шу дру́жбу.','My tsenim nashu druzhbu.','We value our friendship.','Cenimy naszą przyjaźń.','Wir schätzen unsere Freundschaft.',143),
('hangingout-part-1-144','hangingout-part-1','Она очень важна для нас.','Она́ о́чень важна́ для нас.','Ona ochen vazhna dlya nas.','It is very important to us.','Jest dla nas bardzo ważna.','Sie ist uns sehr wichtig.',144),
('hangingout-part-1-145','hangingout-part-1','Мы поддерживаем хорошие отношения.','Мы подде́рживаем хоро́шие отноше́ния.','My podderzhivayem khoroshie otnosheniya.','We maintain good relationships.','Utrzymujemy dobre relacje.','Wir pflegen gute Beziehungen.',145),
('hangingout-part-1-146','hangingout-part-1','Мы регулярно встречаемся.','Мы регуля́рно встреча́емся.','My regulyarno vstrechayemsya.','We meet regularly.','Spotykamy się regularnie.','Wir treffen uns regelmäßig.',146),
('hangingout-part-1-147','hangingout-part-1','Я всегда рад их видеть.','Я всегда́ рад их ви́деть.','Ya vsegda rad ikh videt.','I am always happy to see them.','Zawsze cieszę się, gdy ich widzę.','Ich freue mich immer, sie zu sehen.',147),
('hangingout-part-1-148','hangingout-part-1','Они делают мою жизнь лучше.','Они́ де́лают мою́ жизнь лу́чше.','Oni delayut moyu zhizn luchshe.','They make my life better.','Sprawiają, że moje życie jest lepsze.','Sie machen mein Leben besser.',148),
('hangingout-part-1-149','hangingout-part-1','Я благодарен за таких друзей.','Я благода́рен за таки́х друзе́й.','Ya blagodaren za takikh druzey.','I am grateful for friends like these.','Jestem wdzięczny za takich przyjaciół.','Ich bin dankbar für solche Freunde.',149),
('hangingout-part-1-150','hangingout-part-1','Наша дружба будет долгой.','На́ша дру́жба бу́дет до́лгой.','Nasha druzhba budet dolgoy.','Our friendship will last a long time.','Nasza przyjaźń będzie trwała długo.','Unsere Freundschaft wird lange halten.',150)
